1	import type { Cart } from '@/types/cart';
2	
3	const STORAGE_KEY = 'mockhub-checkout-review-passed';
4	
5	/**
6	 * Fingerprints the cart so the review gate auto-invalidates when items
7	 * are added/removed or prices change. Includes subtotal so a price drift
8	 * between review and payment forces another review.
9	 */
10	export function cartReviewFingerprint(cart: Cart): string {
11	  const itemKey = cart.items
12	    .map((item) => `${item.id}:${item.priceAtAdd}:${item.currentPrice}`)
13	    .join(',');
14	  return `${cart.id}|${cart.subtotal}|${itemKey}`;
15	}
16	
17	export function markReviewPassed(cart: Cart): void {
18	  try {
19	    sessionStorage.setItem(STORAGE_KEY, cartReviewFingerprint(cart));
20	  } catch {
21	    // sessionStorage unavailable (private mode, etc.) makes the gate always block.
22	  }
23	}
24	
25	export function hasReviewPassed(cart: Cart): boolean {
26	  try {
27	    return sessionStorage.getItem(STORAGE_KEY) === cartReviewFingerprint(cart);
28	  } catch {
29	    return false;
30	  }
31	}
32	
33	export function clearReviewPassed(): void {
34	  try {
35	    sessionStorage.removeItem(STORAGE_KEY);
36	  } catch {
37	    // no-op
38	  }
39	}
