27	export function CheckoutPage() {
28	  const { data: cart, isLoading } = useCart();
29	  const checkoutMutation = useCheckout();
30	  const navigate = useNavigate();
31	  const [paymentTab, setPaymentTab] = useState<string>('mock');
32	
33	  // Stripe flow state
34	  const [clientSecret, setClientSecret] = useState<string | null>(null);
35	  const [stripeOrderTotal, setStripeOrderTotal] = useState<number | null>(null);
36	  const [isSettingUpStripe, setIsSettingUpStripe] = useState(false);
37	  const [stripeReady, setStripeReady] = useState(false);
38	
39	  const [isMockProcessing, setIsMockProcessing] = useState(false);
40	
41	  const handleMockCheckout = useCallback(async () => {
42	    setIsMockProcessing(true);
43	    try {
44	      const order = await new Promise<{ orderNumber: string }>((resolve, reject) => {
45	        checkoutMutation.mutate(
46	          { paymentMethod: 'MOCK' },
47	          {
48	            onSuccess: (o) => resolve({ orderNumber: o.orderNumber }),
49	            onError: reject,
50	          },
51	        );
52	      });
53	
54	      const intent = await createPaymentIntent(order.orderNumber);
55	      const confirmation = await confirmPayment(intent.paymentIntentId);
56	      toast.success('Payment successful!');
57	      navigate(`/orders/${confirmation.orderNumber}/confirmation`);
58	    } catch {
59	      toast.error('Payment failed. Please try again.');
60	    } finally {
61	      setIsMockProcessing(false);
62	    }
63	  }, [checkoutMutation, navigate]);
64	
65	  const handleStartStripe = useCallback(async () => {
66	    setIsSettingUpStripe(true);
67	    try {
68	      // Step 1: Create the order (this clears the cart)
69	      const order = await new Promise<{ orderNumber: string; total: number }>((resolve, reject) => {
70	        checkoutMutation.mutate(
71	          { paymentMethod: 'STRIPE' },
72	          {
73	            onSuccess: (o) => resolve({ orderNumber: o.orderNumber, total: o.total }),
74	            onError: reject,
75	          },
76	        );
77	      });
78	      setStripeOrderTotal(order.total);
79	
80	      // Step 2: Create a payment intent
81	      const intent = await createPaymentIntent(order.orderNumber);
82	      setClientSecret(intent.clientSecret);
83	      setStripeReady(true);
84	    } catch {
85	      toast.error('Failed to set up Stripe payment. Please try again.');
86	    } finally {
87	      setIsSettingUpStripe(false);
88	    }
89	  }, [checkoutMutation]);
90	
91	  const handleStripeSuccess = useCallback(
92	    async (paymentIntentId: string) => {
93	      try {
94	        const confirmation = await confirmPayment(paymentIntentId);
95	        toast.success('Payment successful!');
96	        navigate(`/orders/${confirmation.orderNumber}/confirmation`);
97	      } catch {
98	        toast.error('Payment confirmation failed. Please check your orders.');
99	        navigate(ROUTES.ORDERS);
100	      }
101	    },
102	    [navigate],
103	  );
104	
105	  const handleStripeError = useCallback((message: string) => {
106	    toast.error(message);
107	  }, []);
108	
109	  // Once payment completes (mock or stripe) the cart is cleared on the server.
110	  // Clear the review gate too so a future cart cycle re-enters review.
111	  useEffect(() => {
112	    if (cart && cart.items.length === 0) {
113	      clearReviewPassed();
114	    }
115	  }, [cart]);
116	
117	  if (isLoading) {
118	    return (
119	      <div className="mx-auto max-w-4xl px-4 py-6 sm:px-6 lg:px-8">
120	        <Skeleton className="mb-6 h-8 w-48" />
121	        <div className="grid gap-6 lg:grid-cols-2">
122	          <div className="space-y-3">
123	            {Array.from({ length: 3 }, (_, i) => i).map((n) => (
124	              <Skeleton key={`skeleton-${n}`} className="h-24 w-full" />
125	            ))}
126	          </div>
127	          <Skeleton className="h-64 w-full" />
128	        </div>
129	      </div>
130	    );
131	  }
132	
133	  // Gate: direct nav to /checkout with a fresh cart bounces back to review.
134	  // Skip when a payment flow is already in flight (cart may have just cleared).
135	  const inPaymentFlow = stripeReady || isMockProcessing;
136	  if (!inPaymentFlow && cart && cart.items.length > 0 && !hasReviewPassed(cart)) {
137	    return <Navigate to={ROUTES.CHECKOUT_REVIEW} replace />;
138	  }
139	
140	  // Show empty state only if cart is empty AND we're not in a payment flow
141	  if (!stripeReady && !isMockProcessing && (!cart || cart.items.length === 0)) {
142	    return (
143	      <div className="mx-auto max-w-4xl px-4 py-6 sm:px-6 lg:px-8">
144	        <EmptyState
145	          icon={ShoppingCart}
146	          title="Nothing to checkout"
147	          description="Add tickets to your cart first."
148	          action={{ label: 'Browse Events', href: ROUTES.EVENTS }}
149	        />
150	      </div>
151	    );
152	  }
153	
154	  const total = stripeOrderTotal ?? (cart ? cart.subtotal + cart.subtotal * SERVICE_FEE_RATE : 0);
155	
156	  return (
157	    <div className="mx-auto max-w-4xl px-4 py-6 sm:px-6 lg:px-8">
158	      <h1 className="mb-6 text-2xl font-bold">Checkout</h1>
159	
160	      <div className="grid gap-6 lg:grid-cols-2">
161	        {/* Order Review */}
162	        {cart && cart.items.length > 0 ? (
163	          <OrderReview cart={cart} />
